return items.map((item) => {
  const tz = 'America/Guayaquil';
  const nowLocal = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
  const yyyy = nowLocal.getFullYear();
  const mm = String(nowLocal.getMonth() + 1).padStart(2, '0');
  const dd = String(nowLocal.getDate()).padStart(2, '0');
  const forDate = `${yyyy}-${mm}-${dd}`;
  const yyyymmdd = `${yyyy}${mm}${dd}`;

  item.json.cfg = {
    report: {
      tz,
      forDate,
      yyyymmdd,
      exportBasePath: './public_html/BANCO_SOLIDARIO',
      exportFolderPath: `./public_html/BANCO_SOLIDARIO/${yyyymmdd}`,
      cedente: 'BANCO SOLIDARIO',
      tipoCartera: 'Administrativo',
      canalGestion: 'VOZ IA',
      gestoresAsignados: '1',
      diasLaborados: '1',
      observaciones: ' '
    }
  };

  return item;
});

const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
const dd = cfg.report.yyyymmdd;

const safeCount = (nodeName) => {
  try {
    return $items(nodeName, 0, 0).length;
  } catch (e) {
    return 0;
  }
};

const prodRows = safeCount('CONSULTA PRODUCTIVIDAD (DIA)');
const gestRows = safeCount('CONSULTA GESTION (DIA)');

return [{
  json: {
    status: 'ok',
    fecha_reporte: cfg.report.forDate,
    carpeta_destino: cfg.report.exportFolderPath,
    archivo_productividad: `reporte_productividad_${dd}.xlsx`,
    archivo_gestion: `reporte_gestion_${dd}.xlsx`,
    filas_productividad: prodRows,
    filas_gestion: gestRows,
    nota: 'Exportacion XLSX y carga SFTP ejecutadas',
    advertencia: gestRows === 0 ? 'Rama gestion sin ejecucion o sin datos' : null
  }
}];

